<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    checksum</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> TEXT</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">-- SHA-256 hash</span></span>
